      <div style="color: rgba(235, 235, 245, 0.4); font-size: 11px">
        {{ t('pref_tutorials_tip') }}
      </div>
    </IosCard>

    <!-- 数据备份 -->
    <IosCard :title="t('pref_data_backup')" icon="fa-solid fa-database" icon-color="#60a5fa">
      <div style="display: flex; flex-direction: column; gap: 16px">
        <div style="display: flex; justify-content: space-between; align-items: center">
          <div>
            <div style="font-size: 15px; font-weight: 500; color: #fff">{{ t('pref_export_data') }}</div>
            <div style="font-size: 12px; color: rgba(235, 235, 245, 0.6)">{{ t('pref_export_data_desc') }}</div>
          </div>
          <IosButton
            size="small"
            icon="fa-solid fa-download"
            style="background: #007aff; color: white"
            @click="exportData"
          >
            {{ t('pref_export_btn') }}
          </IosButton>
        </div>
        <div style="display: flex; justify-content: space-between; align-items: center">
