                font-size: 11px;
                margin-bottom: 6px;
                white-space: nowrap;
                overflow: hidden;
                text-overflow: ellipsis;
              "
            >
              {{ stats.bySource[source].books.join('、') }}
            </div>
            <div style="display: flex; gap: 6px; font-size: 10px; color: rgba(235, 235, 245, 0.4)">
              <span>蓝: {{ short(stats.bySource[source].c) }}</span>
              <span>绿: {{ short(stats.bySource[source].s) }}</span>
              <span>向: {{ short(stats.bySource[source].v) }}</span>
            </div>
          </div>
        </div>
      </IosCard>

      <!-- 详细列表 -->
      <IosCard title="世界书条目明细" icon="fa-solid fa-list" icon-color="#38bdf8">
        <div v-if="lorebookList.length === 0" style="font-size: 13px; color: rgba(235, 235, 245, 0.5)">
          没有检测到启用的世界书条目。
        </div>
        <div v-else class="table-container">
          <table class="ios-table">
            <thead>
              <tr>
                <th style="text-align: left">世界书</th>
                <th style="text-align: left">来源</th>
                <th style="text-align: right; color: #7dd3fc">蓝灯</th>
                <th style="text-align: right; color: #86efac">绿灯</th>
