            <tbody>
              <tr v-for="row in lorebookList" :key="row.name">
                <td style="color: #fff">{{ row.name }}</td>
                <td style="color: rgba(235, 235, 245, 0.5)">{{ sourceLabels[row.source] }}</td>
                <td style="text-align: right; color: #7dd3fc">{{ short(row.c) }}</td>
                <td style="text-align: right; color: #86efac">{{ short(row.s) }}</td>
                <td style="text-align: right; color: #fde047">{{ short(row.v) }}</td>
                <td style="text-align: right; font-weight: 600; color: #fff">{{ short(row.t) }}</td>
