    <!-- 加载状态已经在 IosButton 上体现，或者是顶部按钮状态 -->
    <div v-if="loading && !stats" style="margin-top: 20px; text-align: center; color: rgba(235, 235, 245, 0.5)">
      正在扫描数据...
    </div>
  </div>
