              border-bottom: 1px solid rgba(255, 255, 255, 0.05);
            "
            @click="toggleExpanded(index)"
          >
            <div style="display: flex; align-items: center; gap: 10px; flex: 1">
              <span style="color: #4a9eff; font-weight: 600; font-size: 14px">#{{ Number(index) + 1 }}</span>
              <span style="color: rgba(235, 235, 245, 0.5); font-size: 12px">
                {{ t('floor') }} {{ item.start_id }} - {{ item.end_id }}
              </span>
            </div>
            <span style="color: rgba(235, 235, 245, 0.3); font-size: 12px">{{ isExpanded(index) ? '▼' : '▶' }}</span>
          </div>

          <div v-show="isExpanded(index)" style="padding: 15px">
            <div style="display: flex; gap: 8px; margin-bottom: 15px">
              <IosButton size="small" style="flex: 1" icon="fa-solid fa-copy" @click="copySummary(item.content)">
                {{ t('copy') }}
